  {@rgba, {g, g, g, a}}
end
def to_rgba({@rgb, {r, g, b}}) do
  {@rgba, {r, g, b, 255}}
end
def to_rgba({@rgba, {r, g, b, a}}) do
  {@rgba, {r, g, b, a}}
end
