  {@rgba, {0, 0, 0, 0}}
end
def to_rgba(:transparent) do
  {@rgba, {0, 0, 0, 0}}
end
def to_rgba(name) when is_atom(name) do
  {r, g, b} = name_to_rgb(name)
  {@rgba, {r, g, b, 255}}
end
def to_rgba({name, a}) when is_atom(name) and is_uint8(a) do
  {r, g, b} = name_to_rgb(name)
  {@rgba, {r, g, b, a}}
end

