def zero() do
  @matrix_zero
end

def identity() do
  @matrix_identity
end

def add(vector2_a, vector2_b)
def add({ax, ay}, {bx, by}) do
  {ax + bx, ay + by}
end

def div(vector2_a, vector2_b)
def div({ax, ay}, s) when is_number(s) do
  {ax / s, ay / s}
end

def invert(vector_2)
def invert({x, y}) do
  {-x, -y}
end

def mul(vector2_a, vector2_b)
def mul({ax, ay}, s) when is_number(s) do
  {ax * s, ay * s}
end

def normalize(vector2)
def normalize({ax, ay}) do
  case Vector2.length({ax, ay}) do
    +0.0 -> {ax, ay}
    len -> {ax / len, ay / len}
  end
end

def round(vector_2)
def round({x, y}) do
  {Kernel.round(x), Kernel.round(y)}
end

def sub(vector2_a, vector2_b)
def sub({ax, ay}, {bx, by}) do
  {ax - bx, ay - by}
end

def trunc(vector_2)
def trunc({x, y}) do
  {Kernel.trunc(x), Kernel.trunc(y)}
end

