def fetch(source_id) when is_atom(source_id) do
  case :ets.lookup(@table, source_id) do
    [{_key, data, _timestamp}] -> {:ok, data}
    _ -> {:error, :not_found}
  end
end

def query(source_id) when is_atom(source_id) do
  case :ets.lookup(@table, source_id) do
    [data] -> {:ok, data}
    _ -> {:error, :not_found}
  end
end

def children(%Scene{children: nil}) do
  {:error, :no_children}
end
def children(%Scene{children: children}) do
  {:ok, Enum.map(children, fn {_, {_, pid, id, _param}} -> {id, pid} end)}
end

def assign_new(%Scene{assigns: assigns} = scene, key, value) do
  %{scene | assigns: Map.put_new(assigns, key, value)}
end

def assign(%Scene{assigns: assigns} = scene, key, value) do
  %{scene | assigns: Map.put(assigns, key, value)}
end

def parent(%Scene{parent: parent}) do
  {:ok, parent}
end

