  events: list(:keyup | :keydown | :status),
  default_handlers: :off | :on | :disable_only
}
| %{type: :button, label: String.t()}
| %{
    type: :form,
    fields: list({field :: atom(), input_output() | nil}),
    submit: String.t() | nil,
    report_changes: %{(field :: atom()) => true},
    reset_on_submit: list(field :: atom())
  }

@type error_output :: %{
  type: :error,
  message: String.t(),
  context:
    {:missing_secret, name :: String.t()}
    | {:interrupt, variant :: :normal | :error, message :: String.t()}
    | {:file_entry_forbidden, name :: String.t()}
    | :dependencies
    | nil
}

@type evaluation_response_metadata :: %{
  interrupted: boolean(),
  errored: boolean(),
  evaluation_time_ms: non_neg_integer(),
  code_markers: list(code_marker()),
  memory_usage: runtime_memory(),
  identifiers_used: list(identifier :: term()) | :unknown,
  identifiers_defined: %{(identifier :: term()) => version :: term()},
  identifier_definitions: list(%{label: String.t(), file: String.t(), line: pos_integer()})
}

@type doctest_report :: %{status: :running | :success, line: pos_integer(), column: pos_integer()}
| %{
    status: :failed,
    line: pos_integer(),
    column: pos_integer(),
    end_line: pos_integer(),
    details: String.t()
  }

@type completion_item :: %{
  label: String.t(),
  kind: completion_item_kind(),
  documentation: String.t() | nil,
  insert_text: String.t()
}

@type details_response :: %{
  range: %{from: non_neg_integer(), to: non_neg_integer()},
  contents: list(String.t()),
  definition: %{file: String.t(), line: pos_integer()} | nil
}

@type runtime_memory :: %{
  atom: size_in_bytes(),
  binary: size_in_bytes(),
  code: size_in_bytes(),
  ets: size_in_bytes(),
  other: size_in_bytes(),
  processes: size_in_bytes(),
  total: size_in_bytes()
}

@type smart_cell_definition :: %{
  kind: String.t(),
  name: String.t(),
  requirement_presets: list(%{name: String.t(), packages: list(package())})
}

@type package_details :: %{
  name: String.t(),
  version: String.t(),
  description: String.t() | nil,
  url: String.t() | nil,
  dependency: dependency()
}

@type editor :: %{
  language: String.t() | nil,
  placement: :bottom | :top,
  source: String.t(),
  intellisense_node: {atom(), atom()} | nil,
  visible: boolean()
}

@type plain_text_output :: %{
  type: :plain_text,
  text: String.t(),
  chunk: boolean(),
  style: [{:color | :font_weight | :font_size, String.Chars.t()}]
}

@type js_view :: %{
  ref: ref(),
  pid: Process.dest(),
  assets: %{
    archive_path: String.t(),
    hash: String.t(),
    js_path: String.t(),
    cdn_url: String.t() | nil
  }
}

@type frame_update_output :: %{
  type: :frame_update,
  ref: frame_ref(),
  update: {:replace, list(output())} | {:append, list(output())}
}

@type grid_output :: %{
  type: :grid,
  outputs: list(t()),
  columns: pos_integer() | tuple(),
  gap: non_neg_integer(),
  max_height: pos_integer() | nil,
  boxed: boolean()
}

@type input_attrs :: %{type: :text, default: String.t(), label: String.t(), debounce: :blur | non_neg_integer()}
| %{
    type: :textarea,
    default: String.t(),
    label: String.t(),
    debounce: :blur | non_neg_integer(),
    monospace: boolean()
  }
| %{type: :password, default: String.t(), label: String.t(), debounce: :blur | non_neg_integer()}
| %{
    type: :number,
    default: number() | nil,
    label: String.t(),
    debounce: :blur | non_neg_integer()
  }
| %{type: :url, default: String.t() | nil, label: String.t(), debounce: :blur | non_neg_integer()}
| %{
    type: :select,
    default: term(),
    label: String.t(),
    options: list({value :: term(), label :: String.t()})
  }
| %{type: :checkbox, default: boolean(), label: String.t()}
| %{
    type: :range,
    default: number(),
    label: String.t(),
    debounce: non_neg_integer(),
    min: number(),
    max: number(),
    step: number()
  }
| %{
    type: :utc_datetime,
    default: NaiveDateTime.t() | nil,
    label: String.t(),
    min: NaiveDateTime.t() | nil,
    max: NaiveDateTime.t() | nil
  }
| %{
    type: :utc_time,
    default: Time.t() | nil,
    label: String.t(),
    min: Time.t() | nil,
    max: Time.t() | nil
  }
| %{type: :date, default: Date.t(), label: String.t(), min: Date.t(), max: Date.t()}
| %{type: :color, default: String.t(), label: String.t(), debounce: :blur | non_neg_integer()}
| %{
    type: :image,
    default: nil,
    label: String.t(),
    format: :rgb | :png | :jpeg,
    size: {pos_integer(), pos_integer()} | nil,
    fit: :match | :contain | :pad | :crop
  }
| %{
    type: :audio,
    default: nil,
    label: String.t(),
    format: :pcm_f32 | :wav,
    sampling_rate: pos_integer()
  }
| %{type: :file, default: nil, label: String.t(), accept: list(String.t()) | :any}

