def delete(length) do
  {:delete, length}
end

def retain(length) do
  {:retain, length}
end

def split_at(op, position)
def split_at({:insert, string}, position) do
  {part_one, part_two} = Livebook.Text.JS.split_at(string, position)
  {insert(part_one), insert(part_two)}
end
def split_at({:retain, length}, position) do
  {retain(position), retain(length - position)}
end
def split_at({:delete, length}, position) do
  {delete(position), delete(length - position)}
end

def request(operation, _) do
  :timer.sleep(40)
  send(self(), {operation.action, operation.params})

  case operation.action do
    :publish ->
      {:ok, %{body: %{message_id: "123", request_id: "345"}}}

    :check_if_phone_number_is_opted_out ->
      case operation.params["phoneNumber"] do
        "+18675309" -> {:ok, %{body: %{is_opted_out: true}}}
        "+1816613" -> {:error, :mock}
        _ -> {:ok, %{body: %{is_opted_out: false}}}
      end

    :opt_in_phone_number ->
      {:ok, %{body: %{request_id: "345"}}}

    _ ->
      {:error, operation}
  end
end

def callback(
      %{
        assigns: %{
          ueberauth_auth:
            %{
              info: %{email: email, phone: phone_number},
              extra: %{raw_info: %{claims: %{"sub" => id}, userinfo: userinfo}}
            } = auth
        }
      } = conn,
      _params
    ) do
  phone_number = PhoneNumber.strip_us_country_code(phone_number)
  role = parse_role({:ok, userinfo})
  mbta_uuid = Map.get(userinfo, "mbta_uuid")
  user = %{id: id, mbta_uuid: mbta_uuid} |> get_or_create_user(email, phone_number, role)
  logout_params = %{post_logout_redirect_uri: page_url(conn, :landing)}

  {:ok, logout_uri} =
    case auth.strategy do
      Ueberauth.Strategy.Oidcc -> UeberauthOidcc.initiate_logout_url(auth, logout_params)
      Ueberauth.Strategy.FakeKeycloak -> {:ok, "/"}
    end

  case user do
    nil ->
      SessionHelper.sign_out(conn, skip_oidc_sign_out: true)

    _ ->
      user = use_props_from_token(user, email, phone_number, role)
      conn |> put_session("logout_uri", logout_uri) |> SessionHelper.sign_in(user)
  end
end
def callback(%{assigns: %{ueberauth_failure: failure}} = conn, _params) do
  Logger.info("Ueberauth failure: #{inspect(failure)}")
  SessionHelper.sign_out(conn, skip_oidc_sign_out: true)
end
def callback(%{assigns: assigns} = conn, params) do
  Logger.warn(
    "Unexpected Ueberauth callback assigns=#{inspect(assigns)} params=#{inspect(params)}"
  )

  SessionHelper.sign_out(conn, skip_oidc_sign_out: true)
end

def use_props_from_token(user, email, phone_number, role) do
  %User{user | email: email, phone_number: phone_number, role: role}
end

