end

def map_to_departure_section(:error, _, _) do
  %NoDataSection{}
end
def map_to_departure_section({:ok, []}, _, _) do
  %NoDataSection{}
end
def map_to_departure_section({:ok, rds_list}, bidirectional, section_count) do
  num_departures_per_section = div(@max_departures_per_rotation, section_count)

  cond do
    headways?(rds_list) ->
      create_headway_section(rds_list)

    no_service?(rds_list) ->
      %NoServiceSection{
        routes:
          rds_list
          |> Enum.flat_map(fn %RDS{state: %NoService{routes: routes}} -> routes end)
          |> Enum.uniq()
      }

    service_ended?(rds_list) ->
      %OvernightSection{
        routes:
          rds_list
          |> Enum.map(fn %RDS{
                           state: %ServiceEnded{
                             last_scheduled_departure: last_scheduled_departure
                           }
                         } ->
            Departure.route(last_scheduled_departure)
          end)
          |> Enum.uniq()
      }

    true ->
      %NormalSection{
        rows:
          create_and_sort_rows(rds_list)
          |> maybe_make_bidirectional(bidirectional)
          |> Enum.take(num_departures_per_section),
        layout: %Layout{},
        header: %Header{}
      }
  end
end

