def informed_routes_at_home_stop(%{
      location_context: location_context,
      alert: %Alert{informed_entities: informed_entities}
    }) do
  rts = location_context.alert_route_types
  home_stop = location_context.home_stop
  route_set = location_context |> LocationContext.route_ids() |> MapSet.new()
  empty_set = MapSet.new()

  uninformed_routes =
    Enum.reduce_while(informed_entities, route_set, fn
      _ie, ^empty_set ->
        {:halt, empty_set}

      %InformedEntity{route_type: nil, stop: nil, route: nil}, uninformed ->
        {:cont, uninformed}

      %InformedEntity{route_type: route_type_id, stop: nil, route: nil}, uninformed ->
        if RouteType.from_id(route_type_id) in rts do
          {:halt, empty_set}
        else
          {:cont, uninformed}
        end

      %InformedEntity{stop: %Stop{id: ^home_stop}, route: nil}, _uninformed ->
        {:halt, empty_set}

      %InformedEntity{stop: %Stop{id: ^home_stop}, route: route}, uninformed ->
        {:cont, MapSet.delete(uninformed, route)}

      %InformedEntity{stop: nil, route: route}, uninformed ->
        {:cont, MapSet.delete(uninformed, route)}

      _ie, uninformed ->
        {:cont, uninformed}
    end)

  route_set |> MapSet.difference(uninformed_routes) |> Enum.to_list()
end

