    ) do
  nil
end
def get_direction_and_route_from_entity(
      %InformedEntity{direction_id: nil, route: "Red", stop: %Stop{id: stop_id}},
      _,
      location
    )
    when location in [:downstream, :boundary_downstream] do
  cond do
    Subway.ashmont_branch_stop?(stop_id) -> {0, "Red-Ashmont"}
    Subway.braintree_branch_stop?(stop_id) -> {0, "Red-Braintree"}
    true -> {0, "Red"}
  end
end
def get_direction_and_route_from_entity(
      %InformedEntity{direction_id: nil, route: "Red", stop: %Stop{id: stop_id}},
      _,
      location
    )
    when location in [:upstream, :boundary_upstream] do
  cond do
    Subway.ashmont_branch_stop?(stop_id) -> {1, "Red-Ashmont"}
    Subway.braintree_branch_stop?(stop_id) -> {1, "Red-Braintree"}
    true -> {1, "Red"}
  end
end
def get_direction_and_route_from_entity(
      %InformedEntity{direction_id: nil, route: route},
      _,
      location
    )
    when location in [:downstream, :boundary_downstream] do
  {0, route}
end
def get_direction_and_route_from_entity(
      %InformedEntity{direction_id: nil, route: route},
      _,
      location
    )
    when location in [:upstream, :boundary_upstream] do
  {1, route}
end
def get_direction_and_route_from_entity(
      %InformedEntity{direction_id: direction_id, route: route},
      _,
      _
    ) do
  {direction_id, route}
end

