def get_relevant_alerts_by_route(alerts) do
  alerts
  |> Stream.flat_map(fn alert ->
    alert |> Utils.alert_routes() |> Enum.uniq() |> Enum.map(fn route -> {alert, route} end)
  end)
  |> Enum.group_by(
    fn {_alert, route} -> route end,
    fn {alert, _route} -> alert end
  )
end

